use std::collections::HashMap;

struct DataRow {
    id: u32,
    data: HashMap<String, String>,
}

trait Visitor {
    fn process_row(&self, row: &DataRow) -> Result<i32, String>;
}

struct CounterVisitor;

impl Visitor for CounterVisitor {
    fn process_row(&self, row: &DataRow) -> Result<i32, String> {
        Ok(1)
    }
}

struct ValidatorVisitor;

impl Visitor for ValidatorVisitor {
    fn process_row(&self, row: &DataRow) -> Result<i32, String> {
        if let Some(value) = row.data.get("status") {
            if value.contains("ok") {
                Ok(1)
            } else {
                Err(format!("Bad status found: {}", value))
            }
        } else {
            Ok(0)
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let row1 = DataRow { id: 1, data: HashMap::from([("status".to_string(), "ok_data".to_string()), ("value".to_string(), "abc".to_string())]) };
    let row2 = DataRow { id: 2, data: HashMap::from([("status".to_string(), "error_bad".to_string()), ("value".to_string(), "xyz".to_string())]) };

    let counter = CounterVisitor;
    println!("Count for row 1: {}", counter.process_row(&row1)?);

    let validator = ValidatorVisitor;
    match validator.process_row(&row2) {
        Ok(val) => println!("Validation passed with value: {}", val),
        Err(e) => println!("Validation failed as expected: {}", e),
    }

    Ok(())
}

use std::collections::HashMap;

struct Resource {
    name: String,
    type_id: u32,
    attributes: HashMap<String, String>,
}

trait Visitor {
    fn visit_vm(&self, vm: &Resource) -> bool;
    fn visit_db(&self, db: &Resource) -> bool;
    fn process_resource(&self, resource: &Resource) -> bool;
}

struct AuditVisitor;
impl Visitor for AuditVisitor {
    fn visit_vm(&self, vm: &Resource) -> bool {
        println!("Auditing VM '{}': Checking network dependencies...", vm.name);
        true
    }
    fn visit_db(&self, db: &Resource) -> bool {
        println!("Auditing DB '{}': Verifying access policies...", db.name);
        false
    }
    fn process_resource(&self, resource: &Resource) -> bool {
        match resource.type_id {
            1 => self.visit_vm(resource),
            2 => self.visit_db(resource),
            _ => false,
        }
    }
}

fn main() {
    let vm = Resource {
        name: "web-01".to_string(),
        type_id: 1,
        attributes: HashMap::from([("region".to_string(), "us-east-1".to_string())]),
    };
    let db = Resource {
        name: "user-store".to_string(),
        type_id: 2,
        attributes: HashMap::from([("size".to_string(), "50GB".to_string())]),
    };
    let unknown = Resource {
        name: "unknown-asset".to_string(),
        type_id: 99,
        attributes: HashMap::new(),
    };

    let visitor = AuditVisitor;
    visitor.process_resource(&vm);
    visitor.process_resource(&db);
    visitor.process_resource(&unknown);
}

use std::collections::HashMap;

trait Visitor {
    fn visit_handshake(&self, handshake: &Handshake) -> String;
}

struct IntegrityChecker;
impl Visitor for IntegrityChecker {
    fn visit_handshake(&self, handshake: &Handshake) -> String {
        format!("Checking integrity of key: {}", handshake.public_key)
    }
}

struct CipherNegotiator;
impl Visitor for CipherNegotiator {
    fn visit_handshake(&self, handshake: &Handshake) -> String {
        format!("Negotiating cipher suite using public key: {}", handshake.public_key)
    }
}

struct Handshake {
    version: String,
    public_key: String,
    cipher_list: Vec<String>,
}

impl Handshake {
    fn new(version: &str, public_key: &str, cipher_list: Vec<&str>) -> Self {
        Handshake {
            version: version.to_string(),
            public_key: public_key.to_string(),
            cipher_list: cipher_list.iter().map(|&s| s.to_string()).collect(),
        }
    }

    fn process_visitor(&self, visitor: &dyn Visitor) -> String {
        visitor.visit_handshake(self)
    }
}

fn main() {
    let handshake = Handshake::new("TLS 1.3", "2024-XYZ", vec!["AES-256", "SHA-384"]);
    let integrity_visitor = IntegrityChecker;
    let cipher_visitor = CipherNegotiator;

    let result1 = handshake.process_visitor(&integrity_visitor);
    println!("Result 1: {}", result1);

    let result2 = handshake.process_visitor(&cipher_visitor);
    println!("Result 2: {}", result2);
}

use std::collections::HashMap;

#[derive(Clone)]
struct DataNode {
    name: String,
    value: i32,
    children: Vec<Box<DataNode>>,
}

trait Visitor {
    fn visit_node(&self, node: &DataNode) -> i32;
    fn calculate_total(&self, node: &DataNode) -> i32;
}

struct NullCheckerVisitor;
impl Visitor for NullCheckerVisitor {
    fn visit_node(&self, node: &DataNode) -> i32 {
        if node.value == 0 {
            return -1;
        }
        -1
    }
    fn calculate_total(&self, node: &DataNode) -> i32 {
        let mut total = node.value;
        for child in &node.children {
            total += self.calculate_total(child);
        }
        total
    }
}

impl DataNode {
    fn process<V: Visitor>(&self, visitor: &V) -> i32 {
        visitor.visit_node(self)
    }
}

fn main() {
    let leaf1 = Box::new(DataNode { name: "A".to_string(), value: 10, children: vec![] });
    let child1 = Box::new(DataNode { name: "B".to_string(), value: 5, children: vec![leaf1] });
    let root = Box::new(DataNode { name: "Root".to_string(), value: 2, children: vec![child1.clone()] });

    let checker = NullCheckerVisitor;
    let check_result = root.process(&checker);
    println!("Check result for root's node processing: {}", check_result);

    let total_visitor = NullCheckerVisitor;
    let total = total_visitor.calculate_total(&root);
    println!("Calculated total across the structure: {}", total);
}

use std::collections::HashMap;

struct ValidationContext { 
    parameters: HashMap<String, String>,
}

trait Validator {
    fn validate(&self, context: &ValidationContext) -> Result<(), String>;
}

struct UserValidator;
impl Validator for UserValidator {
    fn validate(&self, context: &ValidationContext) -> Result<(), String> {
        if context.parameters.get("username").is_none() || context.parameters.get("password").map_or(true, |p| p.len() < 8) {
            return Err("Username is required or password must be at least 8 characters long".to_string());
        }
        Ok(())
    }
}

struct VaultValidator;
impl Validator for VaultValidator {
    fn validate(&self, context: &ValidationContext) -> Result<(), String> {
        if context.parameters.get("vault_id").is_none() || !context.parameters.get("data_hash").unwrap().contains(":") {
            return Err("Vault ID is missing or data hash format is incorrect".to_string());
        }
        Ok(())
    }
}

fn execute_validation(validator: &dyn Validator, context: &ValidationContext) -> Result<(), String> {
    validator.validate(context)
}
